function compileMediaQuery($queries) {
		$compiledQueries = array();
		foreach ($queries as $query) {
			$parts = array();
			foreach ($query as $q) {
				if (!isset($q[0])) {
					continue;
				}
				switch ($q[0]) {
				case "mediaType":
					$parts[] = implode(" ", array_slice($q, 1));
					break;
				case "mediaExp":
					if (isset($q[1], $q[2])) {
						$parts[] = "($q[1]: " .
							$this->compileValue($this->reduce($q[2])) . ")";
					} elseif (isset($q[1])) {
						$parts[] = "($q[1])";
					}
					break;
				case "variable":
					$parts[] = $this->compileValue($this->reduce($q));
					break;
				default:
					error_log('a3-responsive-slider: unknown media query type: ' . var_export($q[0], true));
					break;
				}
			}

			if (!empty($parts)) {
				$compiledQueries[] = implode(" and ", $parts);
			}
		}

		$out = "@media";
		if (!empty($compiledQueries)) {
			$out .= " " .
				implode($this->formatter->selectorSeparator, $compiledQueries);
		}
		return $out;
	}
